const targetX = args.x;
const targetZ = args.z;
const targetY = args.y !== undefined ? args.y : Math.floor(bot.entity.position.y);
const radius = args.radius;

const getBestWeapon = function() {
  return bot.inventory.items().find(function(item) {
    return item.name.includes('sword') || item.name.includes('axe');
  });
};

const weapon = getBestWeapon();
if (weapon) {
  await bot.equip(weapon, 'hand');
}

startBackgroundSkill(bot, 'establish_defensive_position', async function(token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);

  const canContinue = function() { return !token.cancelled && bot.health > 0 && Boolean(bot.entity); };

  try {
    const goal = new goals.GoalNear(targetX, targetY, targetZ, radius);
    await bot.pathfinder.goto(goal);

    while (canContinue()) {
      if (!bot.physicsEnabled) {
        await new Promise(function(r) { setTimeout(r, 100); });
        continue;
      }

      const enemy = bot.nearestEntity(function(entity) {
        return entity.type === 'mob' && (entity.kind === 'Hostile' || entity.kind === 'Monster');
      });

      if (enemy && bot.entity.position.distanceTo(enemy.position) < 20) {
        await bot.lookAt(enemy.position.offset(0, enemy.height, 0));
      } else {
        const pitch = (Math.random() * 0.2) - 0.1;
        const yaw = bot.entity.yaw + (Math.random() * 0.5 - 0.25);
        await bot.look(yaw, pitch);
      }

      await new Promise(function(r) { setTimeout(r, 2000); });
    }
  } catch (err) {
    if (!token.cancelled) {
      console.error('Defensive positioning failed:', err);
    }
  }
});

return "<POSITIONING>: Moving to coordinate (" + targetX + ", " + targetY + ", " + targetZ + ") and scanning for threats.";
